code = """import json
import ast

business_file = locals()['var_function-call-13752562615741184350']
with open(business_file, 'r') as f:
    businesses = json.load(f)

def parse_parking(val):
    if not val or val == 'None' or val == 'False':
        return {}
    if val == 'True':
        return {'generic': True}
    if val.startswith('{'):
        try:
            return ast.literal_eval(val)
        except:
            return {}
    return {}

count_bike = 0
count_any_car = 0
count_lot_garage_valet_validated = 0
count_street_only = 0

final_count_inclusive = 0
final_count_exclusive = 0

for bus in businesses:
    attrs = bus.get('attributes')
    if not attrs or attrs == 'None':
        continue
    if not isinstance(attrs, dict):
        continue

    bp = attrs.get('BikeParking')
    has_bike = (bp == 'True')
    
    cp_str = attrs.get('BusinessParking')
    cp_dict = parse_parking(cp_str)
    
    # Check car parking keys
    # Keys seen: garage, street, validated, lot, valet
    has_garage = cp_dict.get('garage', False)
    has_lot = cp_dict.get('lot', False)
    has_valet = cp_dict.get('valet', False)
    has_validated = cp_dict.get('validated', False)
    has_street = cp_dict.get('street', False)
    
    has_car_inclusive = any(cp_dict.values()) or cp_dict.get('generic')
    
    has_car_exclusive = has_garage or has_lot or has_valet or has_validated or cp_dict.get('generic')
    
    if has_bike or has_car_inclusive:
        final_count_inclusive += 1
        
    if has_bike or has_car_exclusive:
        final_count_exclusive += 1

print("__RESULT__:")
print(json.dumps({
    "inclusive": final_count_inclusive,
    "exclusive": final_count_exclusive
}))"""

